function r(e){return new Intl.NumberFormat("en-US",{style:"currency",currency:"USD"}).format(e)}function a(e){return new Date(e).toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"})}function o(e){return new Date(e).toLocaleString("en-US",{month:"short",day:"numeric",year:"numeric",hour:"2-digit",minute:"2-digit"})}function i(e){const t=new Date(e),n=new Date;return Math.ceil((t.getTime()-n.getTime())/(1e3*60*60*24))}export{a,o as b,i as d,r as f};
